mapper.select:
select c.id as chunkId, c.document_id as documentId, c.chunk_no as chunkNo, c.effective_content as effectiveContent, kd.title as documentTitle, 1 - (cv.embedding <=> cast(#{vectorLiteral} as vector)) as vectorScore, 0 as lexicalScore, 0 as finalScore from t_chunk_vector cv join t_chunk c on c.id::text = cv.id join t_knowledge_document kd on kd.id = c.document_id where c.delete_flag = 0 and c.enabled = true and c.embedding_status = 'SUCCESS' and kd.delete_flag = 0 and kd.status = 'ENABLED' and kd.parse_status = 'SUCCESS'
and true
and coalesce(kd.min_rank_level, 0) <= #{rankLevel} and (kd.visibility_scope <> 'SENSITIVE' or exists ( select 1 from t_document_department_auth dda where dda.document_id = kd.id and dda.department_id = #{departmentId} and dda.delete_flag = 0 ))
and cv.metadata->>'collection_name' = #{collectionName}
order by cv.embedding <=> cast(#{vectorLiteral} as vector) limit #{recallLimit}
